query:
{
  functionApps(
    where: {
      authSettings_SOME: {
        enabled: { eq: true }
        OR: [
          { unauthenticatedClientAction: { eq: "AllowAnonymous" } }
          { unauthenticatedClientAction: { eq: "" } }
          { unauthenticatedClientAction: { eq: null } }
        ]
      }
    }
  ) {
    ...AssetFragment
  }
}
